public interface IFileUploadService
{
    Task<FileUploadResult> UploadFileAsync(IFormFile file, string fileType);
    bool IsValidFileType(string fileName, string fileType);
}

public class FileUploadService : IFileUploadService
{
    private readonly IWebHostEnvironment _environment;
    private readonly Dictionary<string, List<string>> _allowedExtensions = new()
    {
        { "avatar", new List<string> { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp" } },
        { "document", new List<string> { ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx", ".txt", ".csv" } }
    };

    private readonly Dictionary<string, long> _maxFileSizes = new()
    {
        { "avatar", 5 * 1024 * 1024 },
        { "document", 20 * 1024 * 1024 }
    };

    public FileUploadService(IWebHostEnvironment environment)
    {
        _environment = environment;
    }

    public bool IsValidFileType(string fileName, string fileType)
    {
        var extension = Path.GetExtension(fileName).ToLowerInvariant();
        
        if (!_allowedExtensions.ContainsKey(fileType))
            return false;

        return _allowedExtensions[fileType].Contains(extension);
    }

    public async Task<FileUploadResult> UploadFileAsync(IFormFile file, string fileType)
    {
        if (file == null || file.Length == 0)
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = "No file uploaded"
            };
        }

        if (!IsValidFileType(file.FileName, fileType))
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"Invalid file type. Allowed extensions: {string.Join(", ", _allowedExtensions[fileType])}"
            };
        }

        if (file.Length > _maxFileSizes[fileType])
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File size exceeds maximum allowed size of {_maxFileSizes[fileType] / (1024 * 1024)} MB"
            };
        }

        try
        {
            var uploadsFolder = Path.Combine(_environment.WebRootPath, "uploads", fileType);
            if (!Directory.Exists(uploadsFolder))
            {
                Directory.CreateDirectory(uploadsFolder);
            }

            var uniqueFileName = $"{Guid.NewGuid()}_{Path.GetFileName(file.FileName)}";
            var filePath = Path.Combine(uploadsFolder, uniqueFileName);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            var relativePath = $"/uploads/{fileType}/{uniqueFileName}";

            return new FileUploadResult
            {
                Success = true,
                FilePath = relativePath,
                FileName = uniqueFileName,
                OriginalFileName = file.FileName,
                FileSize = file.Length
            };
        }
        catch (Exception ex)
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"Error uploading file: {ex.Message}"
            };
        }
    }
}

public class FileUploadResult
{
    public bool Success { get; set; }
    public string FilePath { get; set; }
    public string FileName { get; set; }
    public string OriginalFileName { get; set; }
    public long FileSize { get; set; }
    public string ErrorMessage { get; set; }
}

[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly IFileUploadService _fileUploadService;

    public FileUploadController(IFileUploadService fileUploadService)
    {
        _fileUploadService = fileUploadService;
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(5 * 1024 * 1024)]
    public async Task<IActionResult> UploadAvatar(IFormFile file)
    {
        var result = await _fileUploadService.UploadFileAsync(file, "avatar");

        if (!result.Success)
        {
            return BadRequest(new { error = result.ErrorMessage });
        }

        return Ok(new
        {
            success = true,
            filePath = result.FilePath,
            fileName = result.FileName,
            originalFileName = result.OriginalFileName,
            fileSize = result.FileSize
        });
    }

    [HttpPost("document")]
    [RequestSizeLimit(20 * 1024 * 1024)]
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        var result = await _fileUploadService.UploadFileAsync(file, "document");

        if (!result.Success)
        {
            return BadRequest(new { error = result.ErrorMessage });
        }

        return Ok(new
        {
            success = true,
            filePath = result.FilePath,
            fileName = result.FileName,
            originalFileName = result.OriginalFileName,
            fileSize = result.FileSize
        });
    }

    [HttpPost("bulk")]
    [RequestSizeLimit(50 * 1024 * 1024)]
    public async Task<IActionResult> UploadMultipleFiles([FromForm] List<IFormFile> files, [FromForm] string fileType = "document")
    {
        if (files == null || !files.Any())
        {
            return BadRequest(new { error = "No files uploaded" });
        }

        var results = new List<object>();

        foreach (var file in files)
        {
            var result = await _fileUploadService.UploadFileAsync(file, fileType);
            
            results.Add(new
            {
                fileName = file.FileName,
                success = result.Success,
                filePath = result.FilePath,
                fileSize = result.FileSize,
                error = result.ErrorMessage
            });
        }

        return Ok(new
        {
            totalFiles = files.Count,
            successCount = results.Count(r => ((dynamic)r).success),
            results
        });
    }
}